import{_ as e,o,c as r,ag as a}from"./chunks/framework.CrllrrHC.js";const g=JSON.parse('{"title":"🪐About Zoro","description":"","frontmatter":{"title":"🪐About Zoro","slug":"about me","date":"2026年05月07日"},"headers":[],"relativePath":"column/my/index.md","filePath":"column/my/index.md","lastUpdated":1778746106000}'),l={name:"column/my/index.md"};function d(n,t,i,s,h,p){return o(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="📟-zoro-系统正在运行-拒绝死循环" tabindex="-1">📟 Zoro: 系统正在运行，拒绝死循环 <a class="header-anchor" href="#📟-zoro-系统正在运行-拒绝死循环" aria-label="Permalink to &quot;📟 Zoro: 系统正在运行，拒绝死循环&quot;">​</a></h1><p>一名深耕后端领域的工程师，始终坚信代码不该困住生活，要跳出固定逻辑，做有温度、有棱角的技术执行者。</p><h2 id="👨💻-逻辑世界-back-end-development" tabindex="-1">👨💻 逻辑世界 | Back-end Development <a class="header-anchor" href="#👨💻-逻辑世界-back-end-development" aria-label="Permalink to &quot;👨💻 逻辑世界 | Back-end Development&quot;">​</a></h2><p>我的日常，一半是和数据库博弈，一半是和代码逻辑死磕，专注后端底层优化与极简架构落地，不做冗余开发，只追极致性能。</p><ul><li><strong>核心技术栈</strong>：深耕后端核心技术，专注数据处理与逻辑开发，追求高效简洁的编码方式，拒绝冗余与低效。</li><li><strong>性能强迫症晚期</strong>：信奉“代码精简至上”，对性能有着极致追求，注重细节优化，力求将每一处损耗降到最低。</li><li><strong>极简架构践行者</strong>：推崇极简架构理念，善于用技术巧思优化体验，不依赖硬件堆砌，兼顾服务器高效利用与稳定运行，打造高效稳定的产品形态。</li><li><strong>开发习惯</strong>：偏爱简洁高效的开发环境与工具，秉持极简主义，拒绝冗余配置，专注核心开发需求，注重服务器资源的合理适配。</li></ul><h2 id="🖱️-物理世界-life-beyond-code" tabindex="-1">🖱️ 物理世界 | Life Beyond Code <a class="header-anchor" href="#🖱️-物理世界-life-beyond-code" aria-label="Permalink to &quot;🖱️ 物理世界 | Life Beyond Code&quot;">​</a></h2><p>脱下代码外衣，我对“极致流畅”的追求从没有停止，从数码到生活物件，始终要求零延迟、高可控，把技术人的严谨刻进日常。</p><ul><li><p><strong>无畏契约超凡选手</strong>：瓦友资深爱好者，专注游戏玩法与操作手感，享受竞技对抗的乐趣，不刻意追求硬件参数，重在体验过程。</p></li><li><p><strong>Android深度玩家</strong>：选择安卓系统，核心是反感苹果生态的数据不互通、可玩性低，且诸多实用软件无法安装；同时坚定支持国产系统生态，偏爱其开放自由的使用体验。</p></li><li><p><strong>网易云音乐 LV9</strong>：资深云村常驻选手，等级全靠深夜 EMO 熬出来，没事就泡在歌单里，主打一个氛围感拉满、情绪全靠音乐兜底。</p></li><li><p><strong>双鱼座</strong>：感性且慢热，内心细腻爱思考，既有程序员的理性逻辑，也自带浪漫随性的生活态度。</p></li><li><h3 id="🧬-mbti-人格特质" tabindex="-1">🧬 MBTI 人格特质<a href="https://www.16personalities.com/ch" target="_blank" rel="noreferrer"></a> <a class="header-anchor" href="#🧬-mbti-人格特质" aria-label="Permalink to &quot;🧬 MBTI 人格特质[](https://www.16personalities.com/ch)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">人格类型</th><th>内向 / 外向</th><th>求真务实 / 天马行空</th><th>感性 / 理性</th><th>运筹帷幄 / 随机应变</th><th>情绪易波动/ 自信果断</th><th>测试时间</th></tr></thead><tbody><tr><td style="text-align:left;">ISFJ-T 守卫者</td><td>64% 内向</td><td>59% 求真务实</td><td>54% 感性</td><td>71% 运筹帷幄</td><td>71% 情绪易波动</td><td>2024-02</td></tr><tr><td style="text-align:left;">ENFJ 教育家</td><td>57% 外向</td><td>64% 天马行空</td><td>51% 感性</td><td>75% 运筹帷幄</td><td>51% 情绪易波动</td><td>2024-09</td></tr><tr><td style="text-align:left;">INFJ-T 提倡者</td><td>71%内向</td><td>60% 天马行空</td><td>55% 感性</td><td>74% 运筹帷幄</td><td>64% 情绪易波动</td><td>2026-05</td></tr></tbody></table></li></ul><h2 id="📝-关于-zoro-blog" tabindex="-1">📝 关于 Zoro Blog <a class="header-anchor" href="#📝-关于-zoro-blog" aria-label="Permalink to &quot;📝 关于 Zoro Blog&quot;">​</a></h2><p>这个博客，是我的个人<strong>技术GC回收站</strong>与<strong>问题备份库</strong>，绝非刻意的技术教学平台。</p><p>创立初衷很简单：记录日常踩过的坑、解决的Bug、梳理的技术思路，避免日后重复踩雷，不用再翻遍失效文档找解决方案。如果这些随手记录的内容，恰好能帮你解决某个技术难题，那便是意外的<strong>计算溢出</strong>，实属惊喜。</p><p>这里只写真实的技术感悟，不制造焦虑，不堆砌干货，做互联网里一个安静的技术备份角落。</p><h2 id="📡-联系与寻址" tabindex="-1">📡 联系与寻址 <a class="header-anchor" href="#📡-联系与寻址" aria-label="Permalink to &quot;📡 联系与寻址&quot;">​</a></h2><ul><li><strong>GitHub 仓库</strong>：<a href="https://github.com/i8zoro8i" target="_blank" rel="noreferrer">i8zoro8i</a>，查看我的开源项目与代码提交记录</li><li><strong>交流方式</strong>：欢迎通过页面底部Giscus评论区发起交流，像建立网络连接一样，随时发起握手，探讨技术、聊聊日常都可</li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><p><strong>“如果不输入，系统就会停滞；如果不输出，内存就会泄漏。”</strong></p><p>保持输入，持续输出，做永远在迭代的技术人，也做永远在前行的生活者。</p></div>',15)])])}const u=e(l,[["render",d]]);export{g as __pageData,u as default};
